from typing import Dict, List, Optional


class TrieNode:
    """A single node in the trie, holding child nodes and an end-of-word flag."""

    def __init__(self) -> None:
        """Initialize an empty node with no children and not marking a word end."""
        self.children: Dict[str, "TrieNode"] = {}
        self.is_end_of_word: bool = False


class Trie:
    """A prefix tree supporting insert, exact search, prefix check, and autocomplete."""

    def __init__(self) -> None:
        """Initialize the trie with an empty root node."""
        self.root: TrieNode = TrieNode()

    def insert(self, word: str) -> None:
        """Insert a word into the trie. Empty strings are ignored."""
        if not word:
            return
        node: TrieNode = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _find_node(self, prefix: str) -> Optional[TrieNode]:
        """Return the node at the end of `prefix`, or None if the path doesn't exist."""
        node: TrieNode = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def search(self, word: str) -> bool:
        """Return True only if the exact complete word exists (not just a prefix)."""
        if not word:
            return False
        node: Optional[TrieNode] = self._find_node(word)
        return node is not None and node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        """Return True if any inserted word starts with the given prefix."""
        if not prefix:
            # An empty prefix matches as long as at least one word was inserted.
            return bool(self.root.children)
        return self._find_node(prefix) is not None

    def autocomplete(self, prefix: str, max_results: int = 5) -> List[str]:
        """Return up to `max_results` words starting with `prefix`, sorted alphabetically.

        Uses DFS from the prefix node to collect completions instead of scanning all words.
        """
        results: List[str] = []
        if max_results <= 0:
            return results

        start: Optional[TrieNode] = self._find_node(prefix)
        if start is None:
            return results

        def dfs(node: TrieNode, path: str) -> None:
            """Depth-first walk collecting complete words; stops once max_results is reached."""
            if len(results) >= max_results:
                return
            if node.is_end_of_word:
                results.append(prefix + path)
                if len(results) >= max_results:
                    return
            # Visit children in sorted order so collected words come out alphabetically.
            for char in sorted(node.children):
                dfs(node.children[char], path + char)
                if len(results) >= max_results:
                    return

        dfs(start, "")
        return results


if __name__ == "__main__":
    trie = Trie()
    for w in ["apple", "app", "application", "apt", "bat", "batch", "bath"]:
        trie.insert(w)

    print('search("app")        =>', trie.search("app"))           # True
    print('search("ap")         =>', trie.search("ap"))            # False
    print('starts_with("ap")    =>', trie.starts_with("ap"))       # True
    print('autocomplete("app")  =>', trie.autocomplete("app"))     # ['app', 'apple', 'application']
    print('autocomplete("bat")  =>', trie.autocomplete("bat"))     # ['bat', 'batch', 'bath']
    print('autocomplete("xyz")  =>', trie.autocomplete("xyz"))     # []
```

A few notes on the design choices:

- **Alphabetical ordering for free**: Since DFS visits children via `sorted(node.children)` and a prefix node's own word (if any) is recorded before descending, completions emerge already sorted — no post-sort needed, and the early-exit checks keep it from exploring more of the tree than `max_results` requires.
- **Edge cases handled**: empty insert (ignored), empty search (`False`), empty prefix in `starts_with` (True iff the trie is non-empty), non-existent prefixes (returns `[]`), single-char words, and `max_results <= 0`.
- **`_find_node` helper** is shared by `search`, `starts_with`, and `autocomplete` to avoid duplicating traversal logic.

